"""Decode outright contract trades from Databento DBN archives."""from __future__ import annotationsfrom collections.abc import Iteratorfrom pathlib import Pathfrom trading_framework.infrastructure.importers.databento.chunk_batch_mapper import (    map_trades_chunk_to_contract_columns,)from trading_framework.infrastructure.importers.databento.contract_chunk_columns import (    ContractChunkColumns,)from trading_framework.infrastructure.importers.databento.instrument_cache import (    InstrumentIdentityCache,)from trading_framework.infrastructure.importers.databento.reader import DatabentoDBNTradeReaderfrom trading_framework.infrastructure.importers.databento.storage_normalizer import (    DatabentoStorageTradeFields,)from trading_framework.infrastructure.observability.profile_context import active_phase_timerfrom trading_framework.market.models import MarketTradeStorageTradeFields = DatabentoStorageTradeFieldsclass DatabentoDBNContractTradeReader:    """Decode Databento trades rows grouped by outright contract symbol."""    def __init__(self, *, chunk_size: int | None = None) -> None:        if chunk_size is None:            self._reader = DatabentoDBNTradeReader()        else:            self._reader = DatabentoDBNTradeReader(chunk_size=chunk_size)    def decode_contract_trades(        self,        path: Path,        *,        product: str,    ) -> tuple[dict[str, list[MarketTrade]], int]:        """Decode outright contract trades and count rejected spread/non-outright rows."""        storage_by_contract, rejected = self.decode_contract_storage_trades(path, product=product)        return {            contract_code: [map_databento_trades_row_from_storage(item) for item in items]            for contract_code, items in storage_by_contract.items()        }, rejected    def decode_contract_chunk_columns(        self,        path: Path,        *,        product: str,    ) -> tuple[dict[str, ContractChunkColumns], int]:        """Decode storage-ready column buffers grouped by outright contract symbol."""        timer = active_phase_timer()        identity_cache = InstrumentIdentityCache(product=product)        columns_by_contract: dict[str, ContractChunkColumns] = {}        rejected_row_count = 0        for chunk in self._reader.iter_raw_chunks(path):            if timer is not None:                with timer.phase("decode.iter_chunk"):                    pass                with timer.phase("decode.map_chunk_batch"):                    rejected_row_count += map_trades_chunk_to_contract_columns(                        chunk,                        identity_cache=identity_cache,                        contract_buffers=columns_by_contract,                    )                continue            rejected_row_count += map_trades_chunk_to_contract_columns(                chunk,                identity_cache=identity_cache,                contract_buffers=columns_by_contract,            )        return columns_by_contract, rejected_row_count    def decode_contract_storage_trades(        self,        path: Path,        *,        product: str,    ) -> tuple[dict[str, list[StorageTradeFields]], int]:        """Decode storage-ready trade fields grouped by outright contract symbol."""        columns_by_contract, rejected_row_count = self.decode_contract_chunk_columns(            path,            product=product,        )        return {            contract_code: _storage_fields_from_columns(columns)            for contract_code, columns in columns_by_contract.items()        }, rejected_row_count    def iter_contract_trades(        self,        path: Path,        *,        product: str,    ) -> Iterator[tuple[str, MarketTrade]]:        """Yield ``(contract_code, MarketTrade)`` for outright ``product`` symbols."""        trades_by_contract, _ = self.decode_contract_trades(path, product=product)        for contract_code in sorted(trades_by_contract):            for trade in trades_by_contract[contract_code]:                yield contract_code, tradedef _storage_fields_from_columns(columns: ContractChunkColumns) -> list[StorageTradeFields]:    """Bridge batch column buffers to legacy per-row storage fields."""    return [        DatabentoStorageTradeFields(            ts_event_ns=columns.ts_event_ns[index],            ts_recv_ns=columns.ts_recv_ns[index],            price_nanos=columns.price_nanos[index],            size=columns.size[index],            instrument_id=columns.instrument_id[index],            sequence=columns.sequence[index],            publisher_id=columns.publisher_id[index],            side=columns.side[index],        )        for index in range(len(columns))    ]def map_databento_trades_row_from_storage(storage: StorageTradeFields) -> MarketTrade:    """Bridge storage-ready fields to a domain trade for legacy validation paths."""    from trading_framework.market.contracts.storage_codec import market_trade_from_storage    return market_trade_from_storage(        ts_event_ns=storage["ts_event_ns"],        ts_recv_ns=storage["ts_recv_ns"],        price_nanos=storage["price_nanos"],        size=storage["size"],        side=storage["side"],        sequence=storage["sequence"],    )